export const HELP_FULL_TEXT: string = "NOTE FOR LLM AGENTS: Always use the --llm flag for structured, parseable output.\n  Example: belz ad show <uuid> --llm\n\nbelz — Belzabar CLI\n\nbelz ad <cmd>  —  Automation Designer\n─────────────────────────────────────────────────────────────────────────────\nbelz ad run <published-id>  :->  Execute a published method with empty payload\nbelz ad run <published-id> '<json>'  :->  Execute with an inline JSON payload string\nbelz ad run <published-id> <file.json>  :->  Execute with payload read from a JSON file\nbelz ad run <published-id> '<json>' --raw  :->  Include raw execution payload in output\n\nbelz ad test <uuid>  :->  Execute a draft method; prompts for inputs interactively, returns service outputs and traces\nbelz ad test <uuid> --inputs <file>  :->  Pass a JSON file of input values (skips interactive prompts)\nbelz ad test <uuid> --verbose  :->  Show detailed execution trace for each step\nbelz ad test <uuid> --force  :->  Bypass cache and fetch a fresh method definition before testing\nbelz ad test <uuid> --raw  :->  Include raw execution payload in output\n\nbelz ad run-suites  :->  Run all saved test suites in suites/; verifies HTTP 200 and non-failed execution\nbelz ad run-suites --env nsm-qa  :->  Run all suites against a specific environment\n\n  category create <name>  Create a new AD category (service).\n\n  export-category <id>  Export every method in a category as JSON.\n\nbelz ad save-suite <uuid> --name <name>  :->  Save a named regression test suite (prompts for inputs interactively)\nbelz ad save-suite <uuid> --name <name> --inputs <file>  :->  Save suite using inputs from a JSON file\n\nbelz ad fetch <uuid|url>  :->  Fetch a method by UUID or AD URL; caches and hydrates service definitions\nbelz ad fetch <uuid|url> --raw  :->  Include raw API response alongside the fetch result\nbelz ad fetch <uuid|url> --env nsm-qa  :->  Fetch from a specific environment\n\n  publish <uuid>        Promote a draft to its published version (draft-guarded).\n\n  import <file>         Import method(s) from an exported JSON file.\n\n  services              List platform services (filter with --internal, --search).\n\nbelz ad find  :->  List all service categories with method counts from the local method index\nbelz ad find list  :->  Explicitly list all service categories with method counts\nbelz ad find pick  :->  Open an interactive fzf picker to quickly select a method\nbelz ad find pick <query>  :->  Open fzf picker with an initial query prefilled\nbelz ad find pick <query> --open  :->  Open the selected method URL in browser after picker selection\nbelz ad find <query>  :->  Search methods and categories by name, alias, UUID, and reference ID\nbelz ad find <query> --limit <N>  :->  Return only the top N ranked matches\nbelz ad find <query> --refresh  :->  Rebuild the index from AD APIs before searching\nbelz ad find <query> --raw  :->  Include raw cached index payload in the command output\n\n  save <file> --uuid <id>  Save a JSON overlay onto a draft (draft-guarded).\n\nbelz ad sql dbs  :->  List available SQL database configurations and auth types\nbelz ad sql run \"<query>\"  :->  Execute a SELECT query against the default DB\nbelz ad sql run \"<query>\" --db <name|id>  :->  Execute SELECT against a specific database\nbelz ad sql update \"<query>\" --db <name|id>  :->  Execute UPDATE or DELETE; returns rows affected\nbelz ad sql insert \"<query>\" --db <name|id>  :->  Execute INSERT; returns rows affected and generated IDs/UUIDs\nbelz ad sql modify \"<query>\" --db <name|id>  :->  Execute DDL (ALTER TABLE, CREATE INDEX, etc.)\nbelz ad sql tui  :->  Start an interactive SQL session (prompts for DB and mode: read|insert|update|modify)\nbelz ad sql tui --db <name|id> --mode <read|insert|update|modify>  :->  Start TUI with pre-selected DB and mode\n\n  outputs <uuid>        Print inputs / variables / outputs contract only.\n\n  test-cases <uuid>     List persistent test cases attached to a method.\n\n  categories            List AD categories; filter with --user / --system.\n\n  export <id>           Export a single method as JSON (optionally to a file).\n\n  child-info <cat> <method>  Resolve a child method's inputs/outputs by name.\n\nbelz ad show <uuid|url>  :->  Display structure and metadata of a method (auto-fetched, 5-min cache)\nbelz ad show <uuid|url> --inputs  :->  Show input argument definitions\nbelz ad show <uuid|url> --services  :->  Show service step names and IDs\nbelz ad show <uuid|url> --service-detail <N>  :->  Show detailed info for the Nth service step\nbelz ad show <uuid|url> --full  :->  Show all details including per-service logic and mappings\nbelz ad show <uuid|url> --force  :->  Bypass cache and fetch a fresh method definition\nbelz ad show <uuid|url> --raw  :->  Include raw payloads in output\n\n  test-case <action>    CRUD + suite execution for persistent test cases.\n\n  history <action> <uuid>  Browse and restore previous versions of a method.\n\n  test-report           Latest test-suite execution report.\n\n  show-code <uuid>      Dump decoded custom-code source for all or one CUSTOM_CODE step.\n\n  state <uuid>          Draft/published linkage, version, and staleness check.\n\n\nbelz pd <cmd>  —  Page Designer\n─────────────────────────────────────────────────────────────────────────────\nbelz pd analyze  :->  Recursively analyze all default pages; collect components and AD method references\nbelz pd analyze <page-id>  :->  Recursively analyze a specific page\nbelz pd analyze <page-id> --compliance  :->  Verify discovered AD IDs against master_ids.txt\n\nbelz pd validate <input>  :->  Validate a page/component config against 10 common PD error patterns\nbelz pd validate <input> --llm  :->  Output validation issues as structured JSON envelope\n\nbelz pd find-ad-methods <page-id>  :->  List all AD method IDs referenced in a page\nbelz pd find-ad-methods <name> --component  :->  List all AD method IDs referenced in a named component\nbelz pd find-ad-methods <page-id> --recursive  :->  Deep-scan all child components and collect every AD method ID\n\nbelz pd find <query>  :->  Search pages and components by name, route, or ID\nbelz pd find list  :->  List all pages (add --components for components)\nbelz pd find pick  :->  Open interactive fzf picker to select a page or component\nbelz pd find pick <query> --open  :->  Open selected item's PD designer URL in browser\nbelz pd find <query> --type page|component  :->  Restrict results to one entity type\nbelz pd find --refresh  :->  Rebuild the 7-day search index from API\n\nbelz pd show <input>  :->  Display overview of a page or component (name, IDs, variable/HTTP/component counts)\nbelz pd show <input> --vars  :->  List all user-defined and derived variables with types\nbelz pd show <input> --http  :->  List all HTTP service calls with AD IDs and triggers\nbelz pd show <input> --components  :->  Show the full layout/component tree\nbelz pd show <input> --var-detail <name>  :->  Show full config for a specific variable or derived (spec code, dependencies)\nbelz pd show <input> --http-detail <N>  :->  Show full config for the Nth HTTP call (input bindings, handlers, transform code)\nbelz pd show <input> --full  :->  Show all sections and all details\nbelz pd show <input> --force  :->  Bypass 5-min cache and fetch fresh config\nbelz pd show <input> --raw  :->  Include raw configuration JSON and source API fields\nbelz pd show <input> --recursive  :->  Include recursive component dependency tree and all AD method IDs\n\n\nbelz tw <cmd>  —  Teamwork\n─────────────────────────────────────────────────────────────────────────────\nbelz tw comments <taskId|url>        :->  Fetch all comments for a Teamwork task\nbelz tw comments <taskId|url> --llm  :->  Output as structured JSON envelope\n\nbelz tw task <taskId|url>        :->  Fetch a Teamwork task with assignees, tags, status, and description\nbelz tw task <taskId|url> --llm  :->  Output as structured JSON envelope\n\n\nbelz <cmd>  —  Top-level\n─────────────────────────────────────────────────────────────────────────────\nbelz envs  :->  List all configured environments and show which is currently active\nbelz envs --env nsm-qa  :->  Check the auth configuration of a specific environment\n\nbelz config get  :->  Show URL, user, password status, and cached token for the active environment\nbelz config get --env nsm-qa  :->  Show config for a specific environment\nbelz config token  :->  Print the raw Bearer token to stdout (for scripting or clipboard copy)\nbelz config token --env nsm-qa  :->  Print the token for a specific environment\nbelz config edit  :->  Interactively add, edit, or remove credentials in ~/.belz/config.json\n\nbelz web               — Manage the Belzabar web app (Next.js, port 65535)\n  belz web [start]     — Start the web app in the background\n  belz web -v          — Start and stream logs to the terminal (foreground)\n  belz web stop        — Stop the running web app\n  belz web restart     — Restart the web app\n  belz web status      — Check if the web app is running\n\nbelz migrate profiles  :->  List available NSM migration profiles (source → target environment pairs)\nbelz migrate profiles --refresh  :->  Bypass cache and force live profile discovery\nbelz migrate run --module PD --ids <uuid> --profile <profile>  :->  Migrate a PD page to the next environment\nbelz migrate run --module AD_Method --ids-file <path> --source-env nsm-dev --target-env nsm-qa  :->  Migrate multiple AD methods using a file of IDs\nbelz migrate run --module AD_Method --ids <uuid> --source-env nsm-dev --target-env nsm-qa --out <dir> --llm  :->  Migrate and capture structured output artifacts\n\nUse 'belz <namespace> <cmd> --help' for full flag documentation and examples.";

export function makeHelpResolver(map: Record<string, string>) {
  return async (cmd: string): Promise<string | null> => map[cmd] ?? null;
}
